    return when {
        parameter.isVarArg ->
            KotlinPsiHeuristics.typeMatches(parameterTypeReference, StandardClassIds.String)
        else ->
            KotlinPsiHeuristics.typeMatches(
                parameterTypeReference,
                StandardClassIds.Array,
                StandardClassIds.String,
