        val functionSymbol = function.symbol
        if (functionSymbol !is KaNamedFunctionSymbol) {
            return false
        }

        if (functionSymbol.name.identifier != "main") {
            return false
        }

        if (!function.returnType.isUnitType) {
            return false
        }
    }
    return true
}

