    Div({ style { padding(25.px) } }) {
        Button(attrs = {
            onClick {
                onCountChange(count - 1)
            }
        }) {
            Text("-")
        }

        Span({ style { padding(15.px) } }) {
            Text("$count")
        }

        Button(attrs = {
            onClick {
                onCountChange(count + 1)
            }
        }) {
            Text("+")
        }
    }
}


